function ModelGeneral:AddShowFinishTips(data)
    if not self._finishTipList then
        self._finishTipList = {}
    end
    table.insert(self._finishTipList, data)
end

function ModelGeneral:CheckShowFinishTip()
    if not self._finishTipList or #self._finishTipList == 0 then
        return
    end

    local hasEnterMain = gModelGeneral:GetHasEnteredCityMap()
    if not hasEnterMain then
        return
    end

    local isInGuide = gModelGuide:IsInGuide()
    if isInGuide then
        return
    end

    local isInPlot = gModelPlot:IsInPlot()
    if isInPlot then
        return
    end

    local inBattle = gModelBattle:ExistPositiveBattle()
    if inBattle then
        return
    end
    local data = table.remove(self._finishTipList, 1)

    if data then
        GF.OpenWndTop("UIQstTip", { data = data })
    end
end
