---保留现场
function ModelGeneral:RecordGameState(noOpenSelWndList)

    if LOG_INFO_ENABLED then
        print("<color=red>record game state </color>")
    end

    self._currentWndList = gLGameUI:GetCurrentUI(noOpenSelWndList)
    local curMap = GF.GetCurMap()
    local mapName, mapArg

    if curMap then
        mapName = curMap:GetMapClassName()
        mapArg = curMap:GetMapArgList()
    end

    if string.isempty(mapName) or mapName == "LBattleMap" then
        mapName = "LCityMap"
        mapArg = nil
    end

    self._currentMap = { mapName = mapName, mapArg = mapArg }
end

function ModelGeneral:RecoverGameState()

    if LOG_INFO_ENABLED then
        print("<color=red>recover game state </color>")
    end

    if self._currentMap then
        local mapName = self._currentMap.mapName
        if mapName == "LInvasionMap" then
            gModelInvasion:EnterMap()
        elseif mapName == "LWonderlandMap" or mapName == "LWonderlordMap" then
            self:WonderlandEntrance()
            --elseif mapName == "LOneNightSpaceMap" then
            --	GF.ChangeMap("LOneNightSpaceMap", true)
        else
            GF.ChangeMap(self._currentMap.mapName, true, self._currentMap.mapArg)
        end
    end

    if self._currentWndList then
        table.sort(self._currentWndList, function(a, b)
            return a.wndSortOrder < b.wndSortOrder
        end)

        for k, v in ipairs(self._currentWndList) do
            gLGameUI:OpenWndWithLayer(v.wndSortLayer, v.wndName, v.wndArgList)
        end

        self._currentWndList = nil
    end
end

