function ModelGeneral:PlayerShowReq(targetId, formationType, systemType, channelId, channelIndex)
    if tonumber(targetId) <= 0 then
        LogError("----------------------targetId错误:" .. targetId)
        return
    end
    if (tostring(gModelPlayer:GetPlayerId()) == tostring(targetId)) then
        GF.ShowMessage(ccClientText(11522))
        return
    end
    local pb = LProtoHelper.CreateProto(LProtoIds.PlayerShowReq)
    pb.playerId = gModelPlayer:GetPlayerId()
    pb.targetId = targetId
    pb.systemType = systemType
    if formationType then
        pb.formationType = formationType
    end
    if channelId then
        pb.channelId = channelId
        pb.channelIndex = channelIndex
    end
    SendMessage(pb, LProtoIds.PlayerShowReq)
end

function ModelGeneral:OnPlayerShowResp(pb)
    local playerInfo = self:SetPlayerInfo(pb.targetContent)
    local combatHeroData = self:SetCombatHeroData(pb.heroData)
    local systemType = pb.systemType
    local draconic = pb.draconic
    -- local treasureList = gModelTreasure:GeneralTreasureListByPb(treasures)

    --self._otherArtifactId = pb.artifactId
    local opentPopType = {
        [LPlayerShowConst.OTHER_SYSTEM] = true,
        [LPlayerShowConst.HERO_DISCUSS] = true,
        [LPlayerShowConst.STORY_WRITER] = true,
        [LPlayerShowConst.BLACKLISET] = true,
    }

    if (opentPopType[systemType]) then
        GF.OpenWnd("UIPerInfoPop", { playerInfo = playerInfo, combatHeroData = combatHeroData, systemType = systemType, treasures = {}, draconic = draconic })
        return
    elseif (systemType == LPlayerShowConst.CHAT_SYSTEM) then
        local channelId = pb.channelId
        local channelIndex = pb.channelIndex
        FireEvent(EventNames.ON_CHAT_TA_CALL, { playerInfo = playerInfo, combatHeroData = combatHeroData, systemType = systemType, draconic = draconic, channelId = channelId, channelIndex = channelIndex, treasures = {} })
        return
    end

    local heroData = {}
    heroData.playerId = pb.playerId
    heroData.playerInfo = playerInfo
    -- heroData.artifactId = pb.artifactId【G公共支持】删除神器功能相关数据
    heroData.power = playerInfo._power
    local formationRefId = combatHeroData._formationRefId
    local heros = combatHeroData._heros
    local grids = combatHeroData._grids
    heroData.matrixRefId = formationRefId
    -- heroData.combatTreasures = pb.combatTreasures

    local prefabNameList = {}
    for k, v in ipairs(heros) do
        local grid = grids[k]
        local pos = gModelFormation:GetIndexByPos(formationRefId, grid)
        local refId = v.refId
        local star = v.star
        local skin = v.skin
        local prefabName, needFlip = gModelHero:GetHeroDisplay(refId, star, skin, true, v.form)

        local bottomImg = gModelHero:GetHeroBottomImgByRefId(refId)
        local race = gModelHero:GetHeroRace(refId)
        local data = {
            prefabName = prefabName,
            bottomImg = bottomImg,
            refId = refId,
            lv = v.lv,
            pos = pos,
            race = race,
            isResonance = v.isResonance,
            skin = v.skin,
            needFlip = needFlip,
        }
        prefabNameList[pos] = data
    end
    heroData.prefabNameList = prefabNameList
    FireEvent(EventNames.ON_ENEMY_DATA_RET, heroData)
end

function ModelGeneral:SetPlayerInfo(playerData)
    local playerInfo = StructPlayerInfo:New()
    playerInfo:CreateByPb(playerData)
    return playerInfo
end

function ModelGeneral:SetCombatHeroData(heroData)
