function ModelGeneral:OnLoginNotifyResp(pb, ret)
    if ret ~= 0 then
        return
    end
    self._loginNotiyInstanceHookTime = pb.instanceHookTime
    self._loginNotiyPinnacleStartTime = pb.PinnacleStartTime
    self._loginNotiyGuildBattleStartTime = pb.GuildBattleStartTime
    self._loginNotiyGuildBossTime = pb.GuildBossTime
    self._dreamFountainFullTime = pb.dreamFountainFullTime
    self._crossWarTempleTime  = pb.crossWarTempleTime
    self._petDreamLandTime  = pb.petDreamLandTime
    self._guildBattleTime = pb.guildBattleTime
