end

function ModelGeneral:GetNoticeWndList()
    local list = {}
    for i, v in pairs(self._noticeWndList) do
        local refId = tonumber(i)
        local time = v.time
        local state = v.state
        local ref = self:GetForeshowRefByRefId(refId)
        if ref then
            local isCheck = gModelFunctionOpen:CheckIsOpened(ref.foreshowFunction)
            if isCheck then
                if i == ModelGeneral.NOTICE_MELEE then
                    if state ~= 1 and state ~= 6 then
                        if state == ModelGuildMelee.STATE_Melee then
                            --战斗阶段
                            table.insert(list, { ref = ref, time = time, state = state })
                        elseif state == ModelGuildMelee.STATE_APPLY and gModelGuildMelee:IsSignUp() then
                            --预备阶段

                        else
                            if self:CheckNoticeTimePara(time, ref) then
                                table.insert(list, { ref = ref, time = time, state = state })
                            end
                        end
                    end
                elseif i == ModelGeneral.NOTICE_HELPERLIGHTENING then
                    table.insert(list, { ref = ref })
                else
                    if state ~= 3 then
                        if self:CheckNoticeTimePara(time, ref) then
                            table.insert(list, { ref = ref, time = time, state = state })
                        end
                    end
                end
            end
        else
            if LOG_INFO_ENABLED then
                printInfoNR("！！！ 打印而已，莫慌      ForeshowRef 表 缺少配置：refId = " .. refId)
            end
        end


    end
    if (gModelEndles:HaveNewSelectBuff()) then
        local ref = self:GetForeshowRefByRefId(ModelGeneral.NOTICE_ENDLES)
        if ref then
            table.insert(list, { ref = ref })
        end
    end

    if gModelSimuFight:IsSimulateRunning() then
        local ref = self:GetForeshowRefByRefId(ModelGeneral.NOTICE_SIMULATE)
        if ref then
            table.insert(list, { ref = ref })
        end
    end

    local ref = self:GetForeshowRefByRefId(ModelGeneral.NOTICE_RACE)
    if ref then
        local funcId = ref.foreshowFunction
        if gModelFunctionOpen:CheckIsOpened(funcId) then
            --local show = gModelRaceGame:IsNoticeShow()
            --if show then
            --	table.insert(list, {ref = ref})
            --end
        end
    end

    local ref = self:GetForeshowRefByRefId(ModelGeneral.NOTICE_GUILD_BOSS)
    if ref and gModelFunctionOpen:CheckIsOpened(ref.foreshowFunction) then
        --#108【G公共支持】删掉联盟领主玩法
        --local isShow,time,state = gModelGuildFeudal:IsShowNotice()
        --if isShow and self:CheckNoticeTimePara(time,ref) then
        --	ref.time = time
        --	ref.state = state
        --	table.insert(list, {ref = ref, time = time, state = state})
        --end

    end

    table.sort(list, function(a, b)
        return a.ref.range < b.ref.range
    end)
    return list
end

function ModelGeneral:CheckNoticeTimePara(time, ref)
    local timeArr = string.split(ref.showTime, ":")
    local hour, min, sec = tonumber(timeArr[1]), tonumber(timeArr[2]), tonumber(timeArr[3])
    return self:GetTodayTimeStamp(time, hour, min, sec)
end

function ModelGeneral:GetTodayTimeStamp(tiem, hour, min, sec)
    --判断是否在当前天时间断内
    local _DateCurrectTime = LUtil.OSDate("*t", GetTimestamp())
    local _DateTodayTime = LUtil.OSTime({ year = _DateCurrectTime.year, month = _DateCurrectTime.month, day = _DateCurrectTime.day, hour = hour, min = min, sec = sec })
    local _DateLaterTime = LUtil.OSTime({ year = _DateCurrectTime.year, month = _DateCurrectTime.month, day = _DateCurrectTime.day + 1, hour = 0, min = 0, sec = 0 })
    if (tiem > _DateTodayTime and tiem < _DateLaterTime) then
        return true
    end
    return false
end

function ModelGeneral:SetAlertList(isClear)
    local alertList = self._alertList
    if not alertList then
        alertList = {}
        self._alertList = alertList
    end
    if isClear then
        self._alertList = {}
        self._alertIdList = ""
        return
    end
    local localAlertList = LPlayerPrefs.SetWndAlert()
    if not string.isempty(localAlertList) then
        self._alertIdList = localAlertList
        local list = string.split(localAlertList, ",")
        for k, v in pairs(list) do
            if not string.isempty(v) then
                local id = tonumber(v)
                alertList[id] = id
            end
        end
    end
end

function ModelGeneral:SetAlertId(id)
    local alertList = self._alertList
    if not alertList then
        alertList = {}
        self._alertList = alertList
    end
    local temp = alertList[id]
    if not temp then
        temp = id
        alertList[id] = temp
        if not self._alertIdList then
            self._alertIdList = id
        else
            self._alertIdList = self._alertIdList .. "," .. id
        end
        LPlayerPrefs.SetWndAlert(self._alertIdList)
    end
end

function ModelGeneral:ClearAlertId(id)
    if self._alertList[id] then
        self._alertList[id] = nil
    end
    local idList = string.split(self._alertIdList, ",")
    local s = ""
    for _, v in ipairs(idList) do
        if tonumber(v) ~= id then
            s = s .. "," .. v
        end
    end
    self._alertIdList = s
    LPlayerPrefs.SetWndAlert(self._alertIdList)
end

function ModelGeneral:FindAlertId(id)
    local alertList = self._alertList
    if not alertList then
        return false
    end
    local findId = alertList[id]
    return findId ~= nil
end

function ModelGeneral:GetAlertList()
    return self._alertList
end

function ModelGeneral:OnGeneralPopResp(pb, ret)
    local refId = pb.refId
    local itemList = {}
    local datas = pb.itemList
    for i = 1, #datas do
        local data = datas[i]
        itemList[i] = {
            itemId = data.itemId,
            count = data.count,
            itype = data.type,
        }
    end
    local alertList = self._alertList
    if not alertList then
        alertList = {}
        self._alertList = alertList
    end
    if alertList[refId] then
        return
    end
    GF.OpenWndTop("UIOrdinTip", { refId = refId, itemList = itemList })
end

function ModelGeneral:OnGeneralRewardResp(pb, ret)
    --local rewardType = {
    --    [1] = "Item",
    --    [2] = "Hero",
    --    [3] = "Equip"
    --}
    local temp = gModelHero:GetHeroBookList()
    local heroMapList = table.clone(temp)
    local title = pb.title
    local itemList = {}
    local datas = pb.itemList
    for i = 1, #datas do
        local data = datas[i]
        local itemType = data.type
        local tab = {
            --itype = rewardType[data.type],
            itype = itemType,
            itemId = data.itemId,
            count = data.count,
            itemNum = data.itemNum,
        }
        if itemType == LItemTypeConst.TYPE_ITEM then
            table.insert(itemList, tab)
        elseif itemType == LItemTypeConst.TYPE_HERO then
            for num = 1, tonumber(data.count) do
                local t = table.clone(tab)
                table.insert(itemList, t)
            end
        elseif itemType == LItemTypeConst.TYPE_EQUIP then
            table.insert(itemList, tab)
        elseif itemType == LItemTypeConst.TYPE_OUTFIT then
            table.insert(itemList, tab)
        elseif itemType == LItemTypeConst.TYPE_PET_EQUIP then
            table.insert(itemList, tab)
            -- 【C宠物系统】删掉宠物系统相关
            -- elseif itemType == LItemTypeConst.TYPE_PET then
            -- 	table.insert(itemList, tab)
        end
    end
    local parameters = pb.parameters
    if #itemList < 1 then
        if LOG_INFO_ENABLED then
            printInfoNR2("协议GeneralRewardResp：", "无奖励数据展示")
        end
        if parameters and #parameters > 0 then
            local portId = parameters[1]
            if portId == "com.ct1.protobuf.DreamTripProto" then
                if LOG_INFO_ENABLED then
                    printInfoNR2("协议GeneralRewardResp：", "梦境之旅为兼容触发下一个事件，无奖励为配置错误，麻烦检查下配置")
                end
                FireEvent(EventNames.ON_DREAMTRIP_SHOWGET, {
                    rewardList = itemList
                })
            end
        end
        return
    end
    local delay = pb.delay == 1 and true or false
    local sceneId = pb.sceneId
    local func = function()
        gModelWndPop:TryOpenPopWnd("UIAward", { itemList = itemList, title = title, delay = delay, sceneId = sceneId, parameters = parameters, heroMapList = heroMapList })
    end
    if self._isStoragePop then
        self._triggerRewardPopFun = func
    else
        if func then
            func()
        end
    end
end

function ModelGeneral:SetIsStoragePop(bool)
    self._isStoragePop = bool
