function ModelGeneral:FormatItemStr(reward, format)
    local finalName, finalCount
    local refId = reward.itemId
    local icon, iconBg = gModelItem:GetItemImgByRefId(refId)    --全部使用图标
    --local color = gModelItem:GetItemNameColorString(refId)
    finalName = string.format("#path=%s#", icon)
    finalCount = tostring(reward.count)-- LUtil.FormatColorStr(reward.count,color)
    local str = string.gsub(format, "%$([%w_]+)", { name = finalName, count = finalCount })
