function ModelGeneral:OnSellGoodsReq(data)
    local pb = LProtoHelper.CreateProto(LProtoIds.SellGoodsReq)
    local pbGoods = pb.goods
    for i, v in ipairs(data) do
        local itype = v.itype
        local num = v.num
        local sellData = pbGoods:add()
        sellData.type = itype
        -- 有id提供id
        local id = v.id
        if id then
            sellData.id = id
        end

        -- 有refId提供refId
        local refId = v.refId
        if refId then
            sellData.refId = refId
        end

        sellData.num = num
    end
    SendMessage(pb, LProtoIds.SellGoodsReq)
end

