function ModelGeneral:OnGeneralRewardDetailResp(pb, ret)
    local showType = pb.showType
    local title = pb.title
    local ways = pb.ways
    local rewardList = {}

    local showHeroList = {}

    --- cxl:
    --- 列表中仅有道具且全部是自动使用126/129类型道具，不弹恭喜获得弹窗
    --- 弹恭喜获得弹窗，并且列表排除自动使用126/129类型道具
    local haveTryHeroAutoUse = false
    local allRewardNum = 0
    local fastItemRewardNum = 0
    local otherItemRewardNum = 0
    --[[	local thingsDetail = pb.thingsDetail
        if thingsDetail then
            local items = thingsDetail.items or {}
            local heroes = thingsDetail.heroes or {}
            local runes = thingsDetail.runes or {}
            local outfits = thingsDetail.outfits or {}
            local golemInfos = thingsDetail.golemInfos or {}
            local crystalInfos = thingsDetail.crystalInfos or {}
            fastItemRewardNum = #items
            allRewardNum = fastItemRewardNum + #heroes + #runes + #outfits
            for i, v in ipairs(items) do
                local item = gModelItem:GetServerDataByPb(v)
                if not gModelItem:CheckIsTryHeroCanAutoUse(item.refId) then
                    --- 不是 自动使用126/129类型道具 加入列表
                    table.insert(rewardList, item)
                    otherItemRewardNum = otherItemRewardNum + 1
                else
                    haveTryHeroAutoUse = true
                end
            end
            for i, v in ipairs(heroes) do
                local hero = gModelHero:GetServerDataByPb(v)
                if hero and hero.isTry then
                    table.insert(showHeroList, {
                        refId = hero.refId
                    })
                end
                table.insert(rewardList, hero)
            end
            for i, v in ipairs(runes) do
                local rune = gModelRune:GetServerDataByPb(v)
                table.insert(rewardList, rune)
            end
            for i, v in ipairs(outfits) do
                local outfit = gModelOutfit:GetServerDataByPb(v)
                table.insert(rewardList, outfit)
            end
            for i, v in ipairs(golemInfos) do
                local golemInfo = gModelGolem:GetGolemInfoFormPb(v)
                table.insert(rewardList, golemInfo)
            end
            for i, v in ipairs(crystalInfos) do
                local crystalInfo = gModelCrystalShard:GetCrystalInfoByPb(v)
                table.insert(rewardList, crystalInfo)
            end
        end]]

    local recordItemList = {}
    local thingsDetail = self:GetThingsDetailInfoByPb(pb.thingsDetail)
    if thingsDetail then
        local items = thingsDetail:GetThingsDetailItems() or {}
        local heroes = thingsDetail:GetThingsDetailHeroes() or {}
        local runes = thingsDetail:GetThingsDetailRunes() or {}
        local outfits = thingsDetail:GetThingsDetailOutfits() or {}
        local golemInfos = thingsDetail:GetThingsDetailGolemInfos() or {}
        local equips = thingsDetail:GetThingsDetailEquips() or {}
        local petEquips = thingsDetail:GetThingsDetailPetEquips() or {}
        -- local crystalInfos = thingsDetail:GetThingsDetailCrystalInfos() or {}【G公共支持】删除伙伴晶石功能相关数据
        -- local petDetailInfo = thingsDetail:GetThingsDetailPetDetailInfo() or {}【C宠物系统】删掉宠物系统相关
        fastItemRewardNum = #items

        allRewardNum = fastItemRewardNum + #heroes + #runes + #outfits
        for i, v in ipairs(items) do
            local item = v.serverData
            if not gModelItem:CheckIsTryHeroCanAutoUse(item.refId) then
                --- 不是 自动使用126/129类型道具 加入列表
                table.insert(rewardList, item)
                table.insert(recordItemList, item)
                otherItemRewardNum = otherItemRewardNum + 1
            else
                haveTryHeroAutoUse = true
            end
        end
        for i, v in ipairs(heroes) do
            local hero = v.serverData
            if hero and hero.isTry then
                table.insert(showHeroList, {
                    refId = hero.refId
                })
            end
            table.insert(rewardList, hero)
        end
        for i, v in ipairs(runes) do
            local rune = v.serverData
            table.insert(rewardList, rune)
        end
        for i, v in ipairs(outfits) do
            local outfit = v.serverData
            table.insert(rewardList, outfit)
        end
        for i, v in ipairs(golemInfos) do
            local golemInfo = v.serverData
            table.insert(rewardList, golemInfo)
        end
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- for i, v in ipairs(crystalInfos) do
        -- 	local crystalInfo = table.clone(v.serverData)
        -- 	local loopTimes = crystalInfo.type == 0 and crystalInfo.num or 1
        -- 	if(crystalInfo.type == 0)then
        -- 		crystalInfo.num = 1
        -- 	end
        -- 	for j = 1, loopTimes do
        -- 		table.insert(rewardList, crystalInfo)
        -- 	end
        -- end
        -- 【C宠物系统】删掉宠物系统相关
        -- for i, v in ipairs(petDetailInfo) do
        -- 	local petDetail = v.serverData
        -- 	table.insert(rewardList, petDetail)
        -- end
        for i, v in ipairs(equips) do
            table.insert(rewardList, v.serverData)
        end
        for i, v in ipairs(petEquips) do
            table.insert(rewardList, v.serverData)
        end
    end

    local isNotRewardOther = fastItemRewardNum - otherItemRewardNum == fastItemRewardNum and allRewardNum == fastItemRewardNum
    if isNotRewardOther and haveTryHeroAutoUse then
        return
    end

    if #showHeroList > 0 then
        gModelGeneral:ShowUpHero(showHeroList)
    end

    if showType == 1 then
        FireEvent(EventNames.ON_DETAIL_SYS_MSG, rewardList)
        if ways == 1401 then
            FireEvent(EventNames.ON_DREAMTRIP_SHOWGET, {
                rewardList = recordItemList
            })
        end
        return
    end




    -- 【G公共支持】删掉小游戏功能
    -- if showType == 2 or showType == 3 then
    -- 	local isSuc = showType == 2
    -- 	gModelMinGame:OpenCommbatRet({
    -- 		openType = 2,
    -- 		wndTipsRefId = isSuc and 270003 or 270004,
    -- 		rewardList = rewardList,
    -- 		gameStatus = showType,
    -- 	})
    -- 	return
    -- end

    local func = function()
        local para = {
            itemList = rewardList,
            recordItemList = recordItemList,
            title = title,
            detail = true,
            ways = ways,
            _isBelowWnd = true,
            _specialJudge = {
                ["UIUpStarSagaSowNew"] = true
            }
        }
        if gLGameUI:FindWndByName("UIRiskRtUpLvl") then
            --等阶级弹窗关闭后再打开奖励弹窗
            gModelGrade:NeedWaitOpenRewardWnd(para)
        else
            if ways == 2103 then
                --活动151的弹窗
                FireEvent(EventNames.WNDOPTIONITEM_GETREWARD_PLAY_ANI, para)
                return
            else
                gModelWndPop:TryOpenPopWnd("UIAward", para)
            end


        end
    end

    if ways == 2166 then
        gModelActivityDreamTrip:SetSkillBossRewardFunc(func)
        return
    elseif (ways == ModelItem.ITEM_WISH_MATCH) then
        local data = gModelWishingMatch:GetCallRewardData(rewardList)
        GF.OpenWnd("UIOrdinYellAward2", data)
        return
    elseif ways == 4112 then
        FireEvent(EventNames.BADGE_SHOW_REWARD,1,func)
        return
    end

    if self._isStoragePop then
        self._triggerRewardPopFun = func
    else
        if func then
            func()
        end
    end
end

