--RUNE_TYPE = 1;//符文&天赋 Resp协议数据返回格式：refid_使用率，refId... ; 说明：refId=RuneSkillRef表id，使用率已经计算好，加上%号就行； 多个用，隔开
--GOLEM_TYPE = 2;//魔偶 Resp协议数据返回格式：refid_使用率，refId... ; 说明：refId=GolemSuitRef表id，使用率已经计算好，加上%号就行； 多个用，隔开
--CORE_TYPE = 3;//核心 Resp协议数据返回格式：refid_使用率，refId... ; 说明：refId=CoreEffectRef表id，使用率已经计算好，加上%号就行； 多个用，隔开
function ModelGeneral:OnHeroRecommendDataResp(pb)
    if not self._heroRecommendMap then
        self._heroRecommendMap = {}
    end
    local dataType = pb.type
    local heroRefId = pb.heroRefId
    local recommendData = pb.recommendData

    local dataMap = self._heroRecommendMap[dataType]
    if not dataMap then
        dataMap = {}
        self._heroRecommendMap[dataType] = dataMap
    end
    local recommendList = {}
    local tmpList = string.split(recommendData, ",") or {}
    for k, v in ipairs(tmpList) do
        local vArr = string.split(v, "_")
        if (vArr and #vArr >= 2) then
            local refId = tonumber(vArr[1])
            local val = tonumber(vArr[2])
            if refId then
                recommendList[refId] = val

            end
        end
    end
    dataMap[heroRefId] = recommendList
end

--RUNE_TYPE = 1;//符文&天赋
--GOLEM_TYPE = 2;//魔偶
--CORE_TYPE = 3;//核心
function ModelGeneral:OnGetHeroRecommendData(dataType, heroRefId)
    if not self._heroRecommendMap then
        return nil
    end
    local dataMap = self._heroRecommendMap[dataType]
    if not dataMap then
        return nil
    end
    return dataMap[heroRefId]
end

