function ModelGeneral:OnAchievementHideNeedWaitPopWndClose(wndName)
    local waitPopWndList = gModelAchievement:GetNeedWaitPopList()
    local haveCheck = false
    for k, v in pairs(waitPopWndList) do
        if v == wndName then
            haveCheck = true
            break
        end
    end

    if not haveCheck then
        return
    end

    if not gModelAchievement:CheckHavePopup() then
        return
    end

    --local hasAccount = gModelBattle:HasAccountWnd()
    local hasPop = gModelWndPop:HasPopWnd()
    if hasPop then
        return
    end
    local hasWaitGuide = gModelGuide:HasWaitGuide()
    if hasWaitGuide then
        return
    end

    local isStroyRunning = gLGpManager:FindStoryCopyGp():IsRunning()
    if isStroyRunning then
        return
    end

    local isInPlot = gModelPlot:IsInPlot()
    if isInPlot then
        return
    end

    local isExistBattle = gModelBattle:ExistPositiveBattle()
    if isExistBattle then
        return
    end

    GF.OpenWndUp("UIFeatHide")
end

