function ModelGeneral:OpenItemInfoTipsFormChat(itemdata, showSkinCode, codeList)
    local itemId, itemType, itemNum = itemdata.itemId or itemdata.refId, itemdata.itemType or itemdata.type, itemdata.itemNum or itemdata.count
    local shoSkinType = false
    local hide = false
    if itemNum == -1 then
        hide = true
    end
    if showSkinCode then
        local itemRefType = gModelItem:GetType(itemId)
        if itemRefType and itemRefType == ModelItem.Item_SKINITEM then
            shoSkinType = true
        end
    end
    if shoSkinType then
        local argList = {
            refId = itemId,
            showNum = itemNum,
            showBagNum = false,
            hide = hide,
            hideOwnText = hide,
            appointBtnCode = codeList or "1016",
        }
        self:OpenItemInfoTipByBtnCode(argList)
    else
        GF.OpenWndUp("UIInip", { refId = itemId, showNum = itemNum, showBagNum = hide, hide = hide, chatType = true })
    end
end

-- hide:指定UIInip上的ItemIcon是否显示数字
function ModelGeneral:OpenItemInfoTip(refId, showNum, showBagNum, hide, hideOwnText, share, shareFunc, chatType, id, showBtn, callFunc, forceNoShowBtn, showBtnNum, itemData)
    if id ~= nil then
        printInfoNR("=== id = " .. id)
    end
    local ref = gModelItem:GetRefByRefId(refId)
    if not ref then
        return
    end
    local wndTipInfo = {
        refId = refId,
        showNum = showNum,
        showBagNum = showBagNum,
        hide = hide, hideOwnText = hideOwnText,
        share = share,
        shareFunc = shareFunc,
        chatType = chatType,
        id = id,
        showBtn = showBtn,
        callFunc = callFunc,
        forceNoShowBtn = forceNoShowBtn,
        showBtnNum = showBtnNum
    }
    local itemType = ref.type
    local tabType = ref.tabType
    local isSkin = false
    local typeDate = string.split(ref.typeDate, "=")
    if itemType == ModelItem.Item_CHARACTERSET and typeDate[1] and typeDate[1] == "4" then
        isSkin = true
    end

    if itemType == ModelItem.Item_SKINITEM or isSkin then
        -- 皮肤详情
        GF.OpenWndUp("UISnTip", { refId = refId, showNum = showNum, showBagNum = showBagNum, hide = hide, hideOwnText = hideOwnText, share = share, shareFunc = shareFunc, chatType = chatType, showBtn = showBtn, callFunc = callFunc, forceNoShowBtn = forceNoShowBtn })
        -- elseif itemType == ModelItem.Item_OUTFIT then
        -- 	self:OutfitItemShow(ref.typeDate)
    elseif itemType == ModelItem.ITEM_CUSTOM_GOLEM then
        GF.OpenWnd("UIGolemItemPop",{refId = refId})
        --【G公共支持】删除伙伴晶石功能相关数据
        -- elseif(itemType == ModelItem.ITEM_CRYSTAL_DRAWING)then
        -- 	local sheetId = tonumber(ref.typeDate)
        -- 	local cfgType = ModelCrystalShard.CrystalDrawingRef
        -- 	local typeCfg = gModelCrystalShard:GetCrystalCfgByType(cfgType)
        -- 	local cfgData = typeCfg[sheetId]
        -- 	local itemNum = showNum
        -- 	local drawingData = {
        -- 		refId = sheetId,
        -- 		type = 1,
        -- 		quality = cfgData.quality,
        -- 		itemRefData = ref,
        -- 		showNum = itemNum,
        -- 		isOwn = false
        -- 	}
        -- 	GF.OpenWnd("WndCrystalShardDrawingsDetails", { itemData = drawingData })
    elseif (itemType == ModelItem.ITEM_WISH_MATCH) then
        if (id) then
            local info = itemData
            local itemRef = gModelItem:GetRefByRefId(wndTipInfo.refId)
            if (itemRef and itemRef.type == ModelItem.ITEM_WISH_MATCH) then
                local endTime = info.extra.endTime
                local rewardCfg = gModelWishingMatch:GetConfigByTypeAndKey(ModelWishingMatch.Item, refId)
                local isDrawEnd = rewardCfg.allDropNum and info.extra.allNum >= rewardCfg.allDropNum or false
                if (GetTimestamp() >= endTime / 1000 or isDrawEnd) then
                    wndTipInfo.appointBtnCode = itemRef.btn or "1008"
                    GF.OpenWndUp("UIInip", wndTipInfo)
                else
                    --GF.OpenWndUp("UIInip", wndTipInfo)
                    GF.OpenWndUp("UIItewPop", { info = info })
                end
            end
        else
            GF.OpenWndUp("UIInip", wndTipInfo)
        end

    elseif itemType == ModelItem.TTEM_TYPE_BADGE then
        GF.OpenWnd("UIBrandTips",{refId = checknumber(typeDate[1]),callFunc = callFunc,noShowBtn = forceNoShowBtn})
    else
        GF.OpenWndUp("UIInip", wndTipInfo)
    end
end

