function ModelGeneral:OutfitItemShow(typeDate)
    local typeDateList = string.split(typeDate, ",")
    for i, v in ipairs(typeDateList) do
        v = string.split(v, "=")
        local outfitRefId = tonumber(v[1])
        local outfitHeroRefId = tonumber(v[3])
        --if outfitHeroRefId <= 0 then outfitHeroRefId = 0 end
        local curSerData = {
            refId = outfitRefId,
            star = 0,
            heroRefId = outfitHeroRefId,
            isItem = true,
            starExp = 0,
            heroId = "0",
            score = gModelOutfit:GetOutfitBaseScoreByRefId(outfitRefId),
            nextHeroRefId = 0,
            _type = LItemTypeConst.TYPE_OUTFIT,
        }
        self:OpenOutfitInfoTip({ curSerData = curSerData, outfitType = 2 }, true)
        break
    end
end

