---道具不足，打开获取来源
function ModelGeneral:CheckItemEnough(itemId, itemNum, showWnd, srcWnd, wnd, itemType, jumpBackCB)
    local own = gModelItem:GetNumByRefId(itemId, nil, itemType)
    local isEnough = own >= itemNum
    if not isEnough and showWnd then
        local layer
        if wnd then
            local wndName = wnd:GetWndName()
            if wndName == "UIGeay" then
                layer = wnd:GetWndSortLayer()
            end
        end
        local needNum = itemNum - own 
        gModelGeneral:OpenGetWayWnd({ itemId = itemId, srcWnd = srcWnd, jumpBackCB = jumpBackCB,needNum=needNum }, layer)
    end
    return isEnough
end

function ModelGeneral:CheckItemListEnough(itemList, srcWnd)
    if not itemList then
        return true
    end
    local isEnough = true
    local itemId, itemNum
    local haveNum
    for i, v in ipairs(itemList) do
        itemId = v.itemId
        itemNum = v.itemNum
        haveNum = gModelItem:GetNumByRefId(itemId)
        isEnough = haveNum >= itemNum
        if not isEnough then
            local wndInst = GF.FindFirstWndByName("UIGeay")
            if not wndInst then
                self:OpenGetWayWnd({ itemId = itemId, srcWnd = srcWnd })
            end
            break
        end
    end
    return isEnough
end

function ModelGeneral:CheckItemListEnoughStatus(itemList)
    if not itemList then
        return true
    end
    local isEnough = true
    local itemId, itemNum
    local haveNum
    for i, v in ipairs(itemList) do
        itemId = v.itemId
        itemNum = v.itemNum
        haveNum = gModelItem:GetNumByRefId(itemId)
        isEnough = haveNum >= itemNum
        if not isEnough then
            break
        end
    end
    return isEnough
end

function ModelGeneral:OpenGetWayWnd(argList, layer)
    local itemId = argList.itemId
    if itemId and itemId == 100305 then
        --- 7.16 策划：灵物新增需求，写死道具打开指定界面
        -- gModelTreasure:OpenGiftView()
        return
    end
    layer = layer or LGameUI.UI_SORTLAYER_UIWND
    gLGameUI:OpenWndWithLayer(layer, "UIGeay", argList)
end

