function ModelGeneral:ShowCommonItemTipWnd(itemdata, extra)
    local itemId, itemType, itemNum = itemdata.itemId or itemdata.refId, itemdata.itemType or itemdata.type or itemdata.itype, itemdata.itemNum or itemdata.count
    local showSkinCode
    local codeList
    if extra then
        showSkinCode = extra.showSkinCode
        codeList = extra.codeList
    end
    if itemType == LItemTypeConst.TYPE_ITEM then
        local shoSkinType = false
        local hide = false
        if itemNum == -1 then
            hide = true
        end
        if showSkinCode then
            local itemRefType = gModelItem:GetType(itemId)
            if itemRefType and itemRefType == ModelItem.Item_SKINITEM then
                shoSkinType = true
            end
        end
        if shoSkinType then
            local argList = {
                refId = itemId,
                showNum = itemNum,
                showBagNum = false,
                hide = hide,
                hideOwnText = hide,
                appointBtnCode = codeList or "1016",
            }
            self:OpenItemInfoTipByBtnCode(argList)
        else
            self:OpenItemInfoTip(itemId, itemNum, false, hide, hide,nil,nil,nil,nil,nil,nil,extra and extra.forceNoShowBtn)
        end
    elseif itemType == LItemTypeConst.TYPE_HERO then
        self:OpenHeroSimpleTip(itemId)
    elseif itemType == LItemTypeConst.TYPE_PET_EQUIP then
        self:OpenEquipInfoTip(itemId, nil, itemNum, true, nil, nil, nil, itemType)
    elseif itemType == LItemTypeConst.TYPE_EQUIP then
        self:OpenEquipInfoTip(itemId, nil, itemNum, true)
        -- 【C宠物系统】删掉宠物系统相关
        -- elseif itemType == LItemTypeConst.TYPE_PET then
        -- 	GF.OpenWnd("WndPetReviewPop",{refId = itemId})
    elseif itemType == LItemTypeConst.TYPE_GOLEM then
		local lvlRefId = gModelGolem:GetGolemLvlRefIdByGolemInfo(itemdata)
		local openType = lvlRefId ~= nil and 2 or 4
		--- 魔偶属性详情界面
		gModelGolem:OpenGolemInfoTip({
			viewType = openType,
			golemData = itemdata,
		})
    end
end

