function ModelGeneral:GetCommonItemColor(itemdata)
    local color
    local itemId = itemdata.itemId or itemdata.refId
    local itemType = itemdata.itemType or itemdata.type or itemdata.itype
    if itemType == LItemTypeConst.TYPE_ITEM then
        color = "#" .. gModelItem:GetItemNameColorString(itemId)
    elseif itemType == LItemTypeConst.TYPE_HERO then
        color = "#" .. gModelHero:GetHeroNameColorByRefId(itemId)
    elseif itemType == LItemTypeConst.TYPE_EQUIP then
        color = "#" .. gModelEquip:GetEquipColorByRefId(itemId, true)
    elseif itemType == LItemTypeConst.TYPE_RUNE then
        color = "#" .. gModelRune:GetRuneColorByRefId(itemId)
    elseif itemType == LItemTypeConst.TYPE_PET then
        color = "#" .. gModelPet:GetPetNameColorByRefId(itemId)
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- elseif itemType == LItemTypeConst.ICON_TYPE_CRYSTAL_SHARD then
        -- 	color = "#" .. gModelCrystalShard:GetItemNameColorByItemData(itemdata)
        -- elseif itemType == LItemTypeConst.ICON_TYPE_CRYSTAL_DRAWING then
        -- 	color = "#" .. gModelCrystalShard:GetItemNameColorByItemData(itemdata)
        -- 【C宠物系统】删掉宠物系统相关
        -- elseif itemType == LItemTypeConst.TYPE_PET then
        -- 	color = "#" .. gModelPetSpace:GetPetNameColor(itemId)
    elseif itemType == LItemTypeConst.TYPE_GOLEM then
		color = "#" .. gModelGolem:GetGolemElementColorByRefId(itemId)
    end
    return color
end

function ModelGeneral:GetCommonItemColorName(itemdata, addSymbol)
    if not addSymbol then
        addSymbol = "+"
    end

    local name = self:GetCommonItemName(itemdata)
    local color = self:GetCommonItemColor(itemdata)
    local itemNum = itemdata.itemNum or itemdata.count
    local temp = string.format("%s%s%s", name, addSymbol, itemNum)
    local colorName = LUtil.FormatColorStr(temp, color)
    return colorName
end

function ModelGeneral:GetCommonItemColorNameNoNum(itemdata)
    local name = self:GetCommonItemName(itemdata)
    local color = self:GetCommonItemColor(itemdata)
