function ModelGeneral:RunOriginConfigCode(code, data)
    if code == 1001 then
        gModelGeneral:OpenGetWayWnd({ itemId = data.refId }, LGameUI.UI_SORTLAYER_UIUP)
    elseif code == 1011 then
        local refId = tonumber(string.split(data.typeDate, "=")[2])
        if refId then
            self:OpenHeroStarPre({ refId = refId })
            --GF.OpenWnd("UISagaStarPre",{refId = refId})
        end
    elseif code == 1002 then
    elseif code == 1003 then
    elseif code == 1004 then
    elseif code == 1005 then
    elseif code == 1006 then
    elseif code == 1007 then
    elseif code == 1008 then
        --GF.OpenWndUp("UISProp", { refId = data.refId, itype = data.itype, id = data.id })
        GF.OpenWndUp("UIEqBreakBack", { refId = data.refId, id = data.id, equip = data.equip, wndRefId = 10045 })

    elseif code == 1009 then
        gModelFunctionOpen:Jump(10300000)
        --FireEvent(EventNames.CHANGE_MAIN_BTN,4)
    elseif code == 1010 then
        local wndId = 50701
        local str
        for i, v in ipairs(data.itemList) do
            local itemRefId, itemNum = v.itemId, v.itemNum
            local name = gModelItem:GetNameByRefId(itemRefId)
            if string.isempty(str) then
                str = name .. "*" .. itemNum
            else
                str = str .. "," .. name .. "*" .. itemNum
            end
        end
        local func = function()
            gModelRune:OnRuneDecomposeReq(data.runeId)
        end
        gModelGeneral:OpenUIOrdinTips({ refId = wndId, para = { str }, func = func })

    elseif code == 1012 then
        local info = {}
        table.insert(info, { refId = data.refId, num = 1 })
        gModelItem:OnItemUseReq(info) --向服务器发送物品使用请求
    elseif code == 1015 then
        local refId = data.refId
        local ref = gModelItem:GetRefByRefId(refId)
        local typeDate = ref.typeDate
        typeDate = string.split(typeDate, "=")
        local skinRefId, skinTime, heroRefId = tonumber(typeDate[1]), tonumber(typeDate[2]), tonumber(typeDate[3])
        local heroRefIdList = gModelHero:GetServerHeroListByRefId(heroRefId)        -- 判断是否有该类型的英雄
        if #heroRefIdList <= 0 then
            gModelGeneral:OpenHeroSkin({ refId = heroRefId, skinRefId = skinRefId, preview = true })
            GF.ShowMessage(ccClientText(17420))--17420 您暂未获得该英雄无法激活使用皮肤
            --GF.ShowMessage(ccClientText(17407))
        else
            local isUse = true
            local skinInfo = gModelHero:GetHeroSkinInfoByRefId(skinRefId)
            if skinInfo then
                local endTime = tonumber(skinInfo.endTime)
                if endTime == -1 then
                    isUse = false
                    local haveNum = gModelItem:GetNumByRefId(refId)
                    local itemName = ccLngText(ref.name)
                    local sell = ref.sell
                    if string.isempty(sell) then
                        -- zc:数值说暂时不填具体的返还道具,所以需要增加个机制,皮肤已激活，但出售为空时,则提示：皮肤已激活
                        GF.ShowMessage(ccClientText(17408))
                        return
                    end
                    local sellList = string.split(sell, "=")
                    local sellNum = tonumber(sellList[3]) * haveNum
                    local sellName = gModelItem:GetNameByRefId(sellList[2])
                    sellName = sellNum .. sellName
                    local func = function()
                        local sellData = { itype = 1, refId = refId, num = haveNum }
                        self:OnSellGoodsReq({ sellData })
                    end
                    self:OpenUIOrdinTips({ refId = 10010, para = { itemName, sellName }, func = func }, true)
                    --[[                else
                                        endTime = endTime / 1000
                                        if endTime > GetTimestamp() then
                                            isUse = false
                                            GF.ShowMessage(ccClientText(17408))
                                        end]]
                end
            end
            if isUse then
                local info = {}
                table.insert(info, { refId = refId, num = 1 })
                gModelItem:OnItemUseReq(info) --向服务器发送物品使用请求
            end
        end
    elseif code == 1016 then
        local refId = data.refId
        local ref = gModelItem:GetRefByRefId(refId)
        local typeDate = ref.typeDate
        typeDate = string.split(typeDate, "=")
        local skinRefId, skinTime, heroRefId = tonumber(typeDate[1]), tonumber(typeDate[2]), tonumber(typeDate[3])
        self:OpenHeroSkin({ skinRefId = skinRefId, preview = true })
    elseif code == 1022 then
        GF.OpenWnd("UIReItemSel", data)
    elseif code == 1024 then
        --GF.OpenWnd("UITmHourGlass", { itemId = data.refId })
    elseif code == 1025 then
        self:ItemSummonOperate(data.refId, data.id, 0)
    elseif code == 1026 then
        self:OpenUIOrdinTips({ refId = 10035, func = function()
            self:ItemSummonOperate(data.refId, data.id, 0)
