function ModelGeneral:OpenUIOrdinTips(para, isTop, notBan, isGuide)

    if not notBan then
        if self:IsInStory() then
            printInfoN("banned by story")
            return
        end
    end

    local refId = para.refId
    local func = para.func
    local sid = para.sid

    local wndData = GameTable.UIWindowAttRef[refId]
    local todayTip
    if wndData and sid then
        todayTip = wndData.todayTip
    end

    local alertId
    if todayTip == 2 then
        --todayTip为2， 同refId，不同sid, 今日不再提示  不共用
        alertId = tonumber(refId .. sid)
    else
        --todayTip为1， 同refId，今日不再提示  共用
        alertId = refId
    end

    if gLGameLanguage:IsJapanRegion() and para.isDiamond then
        --日本，召唤用到钻石时，同一个弹窗id，再弹出1次，直到再次被勾选
        alertId = tonumber(alertId .. ModelItem.ITEM_DIAMOND)
    end

    local isAlert = self:FindAlertId(alertId)
    if isAlert then

        if gLGameLanguage:IsJapanRegion() then
            local isNeed, consumeItemNum = self:CheckNeedMasonryNumTips(para)
            if isNeed then
                local closeFunc = para.closeFunc
                self:ShowCheckMasonryNumTips(consumeItemNum, func, closeFunc)
                return
            end
        end

        if func then
            func()
        end
    else
        if isGuide then
            GF.OpenUIGue("UIOrdinTip", para)
        else
            GF.OpenWnd("UIOrdinTip", para)
        end
    end
end

function ModelGeneral:CheckNeedMasonryNumTips(para)
    local refId = para.refId
    if refId == 50503 then
        return false
    end

    local consumeItemData = para.consume

    local wndData = GameTable.UIWindowAttRef[refId]
    local showRes = wndData.showRes
    local showResData
    if not string.isempty(showRes) then
        local showResList = string.split(showRes, '|')
        local showResId = tonumber(showResList[1])
        showResData = self:GetCommonTipsConsumeItemListByShowResId(showResId, consumeItemData)
    end

    if not showResData then
        return false
    end

    local consumeItemId = showResData.consumeItemId or 0
    local consumeItemNum = showResData.consumeItemNum or 0

    local haveItemNumTruth = gModelItem:GetNumByRefId(consumeItemId, true)
    local isNeedCheckShift = haveItemNumTruth < consumeItemNum
    return isNeedCheckShift, consumeItemNum
end

function ModelGeneral:IsNeedShowCheckMasonryNumTips(consumeItemId, consumeItemNum)
    if consumeItemId ~= ModelItem.ITEM_DIAMOND then
        return false
    end

    local haveItemNumTruth = gModelItem:GetNumByRefId(consumeItemId, true)
    local isNeedCheckShift = haveItemNumTruth < consumeItemNum
    if not isNeedCheckShift then
        return false
    end

    return true
end

function ModelGeneral:ShowCheckMasonryNumTips(consumeItemNum, func, closeFunc)
    local haveItem = gModelItem:GetNumByRefId(ModelItem.ITEM_DIAMOND, true)
    local shiftItemName = gModelItem:GetNameByRefId(ModelItem.ITEM_PAY_DIAMOND)
    local needNum = consumeItemNum - haveItem
    local param = {
        refId = 50503,
        func = func,
        closeFunc = closeFunc,
        para = {
            needNum,
            shiftItemName,
            needNum,
            ccClientText(10179)
        }
    }

    gModelGeneral:OpenUIOrdinTips(param)
end

function ModelGeneral:GetCommonTipsConsumeItemListByShowResId(showResId, consumeItemData)
    if not consumeItemData then
        return nil
    end

    local consumeNum, consumeId
    local consumeData = consumeItemData
    local dataType = type(consumeData)
    if dataType == "table" then
        consumeNum, consumeId = consumeData[1], consumeData[2]
    elseif dataType == "number" and showResId then
        consumeNum, consumeId = consumeData, showResId
    elseif dataType == "string" and showResId then
        consumeNum, consumeId = tonumber(consumeData), showResId
    end

    if not consumeNum or consumeNum <= 0 then
        return nil
    end

    return { consumeItemId = consumeId, consumeItemNum = consumeNum }
end

