function ModelGeneral:GetSysEffListByType(type)
    local typeList = self._sysTypeList or {}
    self._sysTypeList = typeList

    local refIdList = typeList[type]
    if refIdList then
        return refIdList
    end
    refIdList = {}
    typeList[type] = refIdList

    for k, v in pairs(GameTable.SysBuffRef) do
        local effType = v.effectType
        if effType == type then
            table.insert(refIdList, v)
        end
    end
    return refIdList
end

function ModelGeneral:IsGuessPrivilegeActive()
    local effectType = 27
    local ratio = 0
    local isActive = false
    for k, v in pairs(GameTable.SysBuffRef) do
        local effType = v.effectType
        if effType == effectType then
            local tempActive = gModelGrade:GetIsActivatePrivilege(v.refId)
            if tempActive then
                ratio = ratio + tonumber(v.effectValue)
            end
            isActive = tempActive or isActive
        end
    end
    return isActive, ratio
end

