function ModelGeneral:ParsePriviValue_31(value, dataMap)
    local effectStr = value
    local types = string.split(effectStr, ",")
    for k1, v1 in ipairs(types) do
        local numList = LxDataHelper.ParseNumber_Sign(v1, "=")
        local data = {
            combatType = numList[1],
            times = numList[2],
            cd = numList[3],
        }
        dataMap[data.combatType] = data
    end

    return dataMap
end

function ModelGeneral:GetSysEffectValue(sysEffId)
    local list = gModelActivity:GetTowerSkipBuff({ "towerJumpCd1", "towerJumpCd2" })
    if list then
        local actBuffId, actBuffValue = list["towerJumpCd1"], list["towerJumpCd2"]
        if actBuffId and actBuffId == sysEffId then
            return actBuffValue
        end
    end

    local cfg = self:GetSysEffectRef(sysEffId)
    local effectStr = cfg.effectValue
    return effectStr
end

