function ModelGeneral:OpenUniquePopWnd(wndData)
    if not self._curPopWnd then
        self:OpenPopWndImpl(wndData)
    else
        if self._curPopWnd.wnd == wndData.wnd then
            return
        end
        for k, v in ipairs(self._waitWndList) do
            --不要重复
            if v.wnd == wndData.wnd then
                return
            end
        end
        table.insert(self._waitWndList, wndData)
    end

end

function ModelGeneral:OnPopWndClose(wndName)
    if not self._popWnds[wndName] then
        return
    end

    self._curPopWnd = nil

    local waitWnd = table.remove(self._waitWndList, 1)
    if waitWnd then
        self:OpenPopWndImpl(waitWnd)
    end
end

function ModelGeneral:OpenPopWndImpl(wndData)
    self._curPopWnd = wndData
    local layer = wndData.layer
    local wndName = wndData.wnd
    local WndPara = wndData.para
    gLGameUI:OpenWndWithLayer(layer, wndName, WndPara)
end

