function ModelGeneral:CheckIsShowUIUpStarSagaSowNew(heroRefId)
    local heroDisplayLv = gModelHero:GeConfigByKey("heroDisplayLv")
    if (not heroDisplayLv) then
        return true
    end
    local heroRef = gModelHero:GetHeroRef(heroRefId)
    local heroQuality = heroRef.quality
    local playerLvl = gModelPlayer:GetPlayerLv()
    local dispArr = string.split(heroDisplayLv, "|")
    local hasConfig = false
    for i, v in ipairs(dispArr) do
        local data = string.split(v, "=")
        local targetQuality = tonumber(data[1])
        local limitLvl = tonumber(data[2])
        if (heroQuality == targetQuality) then
            hasConfig = true
            if (playerLvl <= limitLvl) then
                return true
            end
        end
    end
    return not hasConfig
end

