function ModelGeneral:CheckShowIgnoredPopGift()
    if not self._ignoredPopGift then
        return
    end

    local curMap = GF.GetCurMap()
    if not curMap then
        return
    end

    if not curMap:IsSameMap("LCityMap") then
        return
    end

    local wnd = GF.FindFirstWndByName("UIMCity")
    if not wnd then
        return
    end

    local curIndex = wnd:GetCurIndex()

    if curIndex ~= 1 then
        return
    end

    if gModelGuide:HasWaitGuide() then
        return
    end

    if not gLGameUI:IsCurMainClean() then
        return
    end

    local wndData = self._ignoredPopGift
    self._ignoredPopGift = nil
    GF.OpenWnd(wndData.uiName, wndData.para)

end

function ModelGeneral:ShowRewardDetailTip(itemdata, uiLayer)
    local itype = itemdata.itype
    local refId = itemdata.refId
    if itype == LItemTypeConst.TYPE_ITEM then
        local num = itemdata.num
        self:OpenItemInfoTipTop(refId, num)
    elseif itype == LItemTypeConst.TYPE_HERO then
        gModelHero:ReqShowHeroTip("", itemdata, nil, nil, uiLayer == "UITop")
    elseif itype == LItemTypeConst.TYPE_RUNE then
        local data = { runeData = itemdata }
        self:OpenRuneInfoTip(data)
    elseif itype == LItemTypeConst.TYPE_OUTFIT then
        local data = {
            curSerData = itemdata,
            outfitType = 2,
        }
        self:OpenOutfitInfoTip(data, true)
    elseif itype == LItemTypeConst.TYPE_EQUIP then
        --直接获取一次品质
        local equipRef = gModelEquip:GetEquipRefByRefId(refId)
        local isSpecial = equipRef.quality >= 7
        if isSpecial then
            --
            local equip = StructEquip:New()
            local tempData = {
                refId = itemdata.refId,
                num = itemdata.num,
            }
            equip:CreateByPb(tempData)

            gModelGeneral:OpenEquipInfoTip(itemdata.refId, 0, 3, false, nil, nil, nil, nil, isSpecial, equip)
        else
            gModelGeneral:OpenEquipInfoTip(refId, nil, nil, true)

        end
    elseif itype == LItemTypeConst.TYPE_PET_EQUIP then
        gModelGeneral:OpenEquipInfoTip(refId, nil, nil, true, nil, nil, nil, itype)
    elseif itype == LItemTypeConst.TYPE_GOLEM then
		gModelGeneral:ShowCommonItemTipWnd(itemdata)
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- elseif itype == LItemTypeConst.ICON_TYPE_CRYSTAL_SHARD then
        -- 	GF.OpenWnd("WndCrystalShardDrawingsDetails", { itemData = itemdata })
        -- elseif itype == LItemTypeConst.ICON_TYPE_CRYSTAL_DRAWING then
        -- 	GF.OpenWnd("WndCrystalShardDrawingsDetails", { itemData = itemdata })
        -- 【C宠物系统】删掉宠物系统相关
        -- elseif itype == LItemTypeConst.TYPE_PET then
        -- 	GF.OpenWnd("WndPetReviewPop", { refId = refId })
    end
end

function ModelGeneral:GetCommonItemShowInfo(itemdata)
    local type = itemdata.itemType
    local refId = itemdata.itemId

    local data = {}
    if type == LItemTypeConst.TYPE_ITEM then
        local ref = gModelItem:GetRefByRefId(refId)
        if ref then
            data.icon = ref.icon
        end
    elseif type == LItemTypeConst.TYPE_RUNE then
        local ref = gModelRune:GetRuneInfoByRefId(refId)
        if ref then
            data.icon = ref.icon
        end
    end

    return data
end

