function ModelGeneral:OpenShareTip(data, func)
    if not gModelFunctionOpen:CheckIsOpened(11700000, true) then
        return
    end
    local shareData = data.shareData
    local shareType = data.shareType
    local channels, namelist = gModelChat:GetShareConfigChannlByRefId(shareType)
    local sList = {}
    for i, v in ipairs(channels) do

        local name = v.name == nil and namelist[i] or v.name
        local btnData = {
            --title = v.name,
            title = name,
            openId = v.sendKey,
            func = function()
                gModelChat:OnChatShareReq(v.channelId, shareType, shareData)
                if func then
                    func(v.channelId)
                end
            end
        }
        table.insert(sList, btnData)
    end

    GF.OpenWndTop("UIBtnLPop", { root = data.root, list = sList, showRight = data.showRight })
end

function ModelGeneral:GetRankIcon(rank)
    if not self._rankIconPathList then
        self._rankIconPathList = {
            "public_num_1",
            "public_num_2",
            "public_num_3",
        }
    end

    return self._rankIconPathList[rank]
end

function ModelGeneral:CheckConsumeFill(itemcfg)
    local items = LxDataHelper.ParseItem(itemcfg)
    if not items then
        return true
    end
    for k, v in ipairs(items) do
        local itemId = v.itemId
        local itemNum = v.itemNum
        local own = gModelItem:GetNumByRefId(itemId)
        if itemNum > tonumber(own) then
            return false, itemId
        end
    end
    return true

end

