function ModelGeneral:OriginJump(originInfo)
    if not originInfo then
        if LOG_INFO_ENABLED then
            printInfoNR("没有originInfo")
        end
        return
    end
    local originRefId = originInfo.originRefId
    local functionId = originInfo.functionId
    local srcWnd = originInfo.srcWnd
    if not self._specialOriginList then
        self._specialOriginList = {
            [ModelGeneral.ORIGIN_JUMP_HEROTRENCH] = function()
                gModelHero:OpenBuyHeroBag()
            end,
        }
    end
    local func = self._specialOriginList[originRefId]
    if func then
        func()
        return
    end
    gModelFunctionOpen:Jump(functionId, srcWnd)
end

