function ModelGeneral:CheckTreaListEqual(oldList, newList)
    local newTreaList = {}
    for k, v in pairs(newList) do
        if v ~= 0 then
            newTreaList[k] = v
        end
    end

    local oldTreaList = {}
    for k, v in pairs(oldList) do
        if v ~= 0 then
            oldTreaList[k] = v
        end
    end

    local oldNum = table.keysize(oldTreaList)
    local newNum = table.keysize(newTreaList)
    if oldNum ~= newNum then
        return false
    else
        for k, v in pairs(newTreaList) do
            local oldValue = oldTreaList[k]
            if oldValue ~= v then
                return false
            end
        end
    end

    return true
end

function ModelGeneral:IsRecordPositive(key)
    self:InitDayInfoRecord()
    local time = self._dayInfoRecord[key]
    if time then
        local dayPast = LUtil.GetDayPast(time)
        if dayPast <= 1 then
            return true
        end
    end
    return false
end

function ModelGeneral:InitDayInfoRecord()
    if not self._dayInfoRecord then
        self._dayInfoRecord = {}
        local str = LPlayerPrefs.dayInfoRecord
        if string.isempty(str) then
            return
        end

        self._dayInfoRecord = JSON.decode(str)
        local removeKey = {}
        for k, v in pairs(self._dayInfoRecord) do
            local dayPast = LUtil.GetDayPast(v)
            if dayPast > 1 then
                table.insert(removeKey, k)
            end
        end

        for k, v in pairs(removeKey) do
            self._dayInfoRecord[v] = nil
        end
    end
end

function ModelGeneral:SetDayInfoRecord(key)
    self:InitDayInfoRecord()
    self._dayInfoRecord[key] = GetTimestamp()

    local removeKey = {}
    for k, v in pairs(self._dayInfoRecord) do
        local dayPast = LUtil.GetDayPast(v)
        if dayPast > 1 then
            table.insert(removeKey, k)
        end
    end

    for k, v in pairs(removeKey) do
        self._dayInfoRecord[v] = nil
    end

    local str = JSON.encode(self._dayInfoRecord)
    LPlayerPrefs.SetDayInfoRecord(str)
end

